CREATE TABLE IF NOT EXISTS users (id SERIAL PRIMARY KEY, email VARCHAR(255) NOT NULL UNIQUE, password_hash TEXT, name VARCHAR(255), role VARCHAR(20) DEFAULT 'viewer', phone VARCHAR(50), job_title VARCHAR(100), trade VARCHAR(100), avatar_url TEXT, company_id INTEGER, permissions JSONB, ui_preferences JSONB, email_preferences JSONB, push_preferences JSONB, timezone VARCHAR(100) DEFAULT 'UTC', language VARCHAR(10) DEFAULT 'en', last_login_at TIMESTAMPTZ, two_factor_enabled BOOLEAN DEFAULT false, two_factor_secret TEXT, deactivated_at TIMESTAMPTZ, created_at TIMESTAMPTZ DEFAULT NOW() NOT NULL, updated_at TIMESTAMPTZ DEFAULT NOW() NOT NULL);
CREATE TABLE IF NOT EXISTS companies (id SERIAL PRIMARY KEY, name VARCHAR(255) NOT NULL, slug VARCHAR(255) NOT NULL UNIQUE, logo_url TEXT, primary_color VARCHAR(7) DEFAULT '#10b981', accent_color VARCHAR(7) DEFAULT '#f59e0b', address TEXT, phone VARCHAR(50), email VARCHAR(255), vat_number VARCHAR(50), registration_number VARCHAR(50), domain VARCHAR(255), website TEXT, stripe_customer_id TEXT, stripe_subscription_id TEXT, plan VARCHAR(50) DEFAULT 'free', max_projects INTEGER DEFAULT 5, max_users INTEGER DEFAULT 10, features JSONB, settings JSONB, deactivated_at TIMESTAMPTZ, created_at TIMESTAMPTZ DEFAULT NOW() NOT NULL, updated_at TIMESTAMPTZ DEFAULT NOW() NOT NULL);
CREATE TABLE IF NOT EXISTS company_users (id SERIAL PRIMARY KEY, company_id INTEGER NOT NULL REFERENCES companies(id), user_id INTEGER NOT NULL REFERENCES users(id), role VARCHAR(20) DEFAULT 'viewer', permissions JSONB, joined_at TIMESTAMPTZ DEFAULT NOW() NOT NULL, UNIQUE(company_id, user_id));
CREATE TABLE IF NOT EXISTS projects (id SERIAL PRIMARY KEY, name VARCHAR(255) NOT NULL, description TEXT, status VARCHAR(20) DEFAULT 'planning', client_name VARCHAR(255), client_email VARCHAR(255), client_phone VARCHAR(50), site_address TEXT, site_lat TEXT, site_lng TEXT, geofence_radius INTEGER DEFAULT 200, contract_type VARCHAR(100), contract_number VARCHAR(255), budget TEXT, budget_amount TEXT, start_date TIMESTAMPTZ, end_date TIMESTAMPTZ, actual_completion_date TIMESTAMPTZ, company_id INTEGER REFERENCES companies(id), created_by INTEGER REFERENCES users(id), created_at TIMESTAMPTZ DEFAULT NOW() NOT NULL, updated_at TIMESTAMPTZ DEFAULT NOW() NOT NULL);
CREATE TABLE IF NOT EXISTS tasks (id SERIAL PRIMARY KEY, title VARCHAR(255) NOT NULL, description TEXT, priority VARCHAR(20) DEFAULT 'medium', status VARCHAR(20) DEFAULT 'not_started', progress INTEGER DEFAULT 0, project_id INTEGER REFERENCES projects(id), assigned_to_id INTEGER REFERENCES users(id), parent_task_id INTEGER, created_by INTEGER REFERENCES users(id), company_id INTEGER REFERENCES companies(id), start_date TIMESTAMPTZ, due_date TIMESTAMPTZ, completed_at TIMESTAMPTZ, estimated_hours TEXT, trade VARCHAR(100), is_milestone BOOLEAN DEFAULT false, created_at TIMESTAMPTZ DEFAULT NOW() NOT NULL, updated_at TIMESTAMPTZ DEFAULT NOW() NOT NULL);
CREATE TABLE IF NOT EXISTS defects (id SERIAL PRIMARY KEY, number TEXT NOT NULL, title TEXT NOT NULL, description TEXT, status TEXT DEFAULT 'open', priority TEXT DEFAULT 'medium', type TEXT DEFAULT 'snagging', location TEXT, room_reference TEXT, trade TEXT, project_id INTEGER REFERENCES projects(id), company_id INTEGER REFERENCES companies(id), assigned_to_id INTEGER REFERENCES users(id), reported_by INTEGER REFERENCES users(id), resolved_at TIMESTAMPTZ, resolved_by INTEGER REFERENCES users(id), resolution_note TEXT, created_at TIMESTAMPTZ DEFAULT NOW() NOT NULL, updated_at TIMESTAMPTZ DEFAULT NOW() NOT NULL);
CREATE TABLE IF NOT EXISTS inspections (id SERIAL PRIMARY KEY, title TEXT NOT NULL, description TEXT, status TEXT DEFAULT 'scheduled', type TEXT DEFAULT 'general', location TEXT, project_id INTEGER REFERENCES projects(id), company_id INTEGER REFERENCES companies(id), inspector_id INTEGER REFERENCES users(id), assigned_to_id INTEGER REFERENCES users(id), due_date TIMESTAMPTZ, completed_at TIMESTAMPTZ, score INTEGER, created_at TIMESTAMPTZ DEFAULT NOW() NOT NULL, updated_at TIMESTAMPTZ DEFAULT NOW() NOT NULL);
CREATE TABLE IF NOT EXISTS rfis (id SERIAL PRIMARY KEY, number TEXT NOT NULL, title TEXT NOT NULL, question TEXT, answer TEXT, status TEXT DEFAULT 'draft', priority TEXT DEFAULT 'medium', project_id INTEGER REFERENCES projects(id), company_id INTEGER REFERENCES companies(id), created_by INTEGER REFERENCES users(id), assigned_to_id INTEGER REFERENCES users(id), due_date TIMESTAMPTZ, date_submitted TIMESTAMPTZ, date_answered TIMESTAMPTZ, answered_by INTEGER REFERENCES users(id), closed_by INTEGER REFERENCES users(id), closed_at TIMESTAMPTZ, closed_reason TEXT, created_at TIMESTAMPTZ DEFAULT NOW() NOT NULL, updated_at TIMESTAMPTZ DEFAULT NOW() NOT NULL);
CREATE TABLE IF NOT EXISTS incidents (id SERIAL PRIMARY KEY, title TEXT NOT NULL, description TEXT, incident_type TEXT, severity TEXT DEFAULT 'low', status TEXT DEFAULT 'open', location TEXT, immediate_actions TEXT, root_cause_id INTEGER, cost_impact INTEGER, schedule_impact INTEGER, project_id INTEGER REFERENCES projects(id), company_id INTEGER REFERENCES companies(id), reported_by INTEGER REFERENCES users(id), resolved_by INTEGER REFERENCES users(id), resolved_at TIMESTAMPTZ, investigation_notes TEXT, corrective_actions TEXT, created_at TIMESTAMPTZ DEFAULT NOW() NOT NULL, updated_at TIMESTAMPTZ DEFAULT NOW() NOT NULL);
CREATE TABLE IF NOT EXISTS permits (id SERIAL PRIMARY KEY, permit_number TEXT NOT NULL, title TEXT NOT NULL, description TEXT, permit_type TEXT DEFAULT 'general', risk_level TEXT DEFAULT 'medium', status TEXT DEFAULT 'draft', location TEXT, validity_period TEXT, start_date TIMESTAMPTZ, end_date TIMESTAMPTZ, project_id INTEGER REFERENCES projects(id), company_id INTEGER REFERENCES companies(id), holder_id INTEGER REFERENCES users(id), issued_by INTEGER REFERENCES users(id), revoked_by INTEGER REFERENCES users(id), revoked_at TIMESTAMPTZ, revoke_reason TEXT, created_at TIMESTAMPTZ DEFAULT NOW() NOT NULL, updated_at TIMESTAMPTZ DEFAULT NOW() NOT NULL);
CREATE TABLE IF NOT EXISTS daily_reports (id SERIAL PRIMARY KEY, report_number TEXT NOT NULL, report_date TIMESTAMPTZ NOT NULL, description TEXT, status TEXT DEFAULT 'draft', weather_summary TEXT, temperature TEXT, wind_speed TEXT, rain_amount TEXT, site_conditions TEXT, work_areas TEXT, work_completed TEXT, delays TEXT, visitors TEXT, safety_observations TEXT, quality_notes TEXT, issues TEXT, instructions TEXT, created_by INTEGER REFERENCES users(id), project_id INTEGER REFERENCES projects(id), company_id INTEGER REFERENCES companies(id), created_at TIMESTAMPTZ DEFAULT NOW() NOT NULL, updated_at TIMESTAMPTZ DEFAULT NOW() NOT NULL);
CREATE TABLE IF NOT EXISTS timesheets (id SERIAL PRIMARY KEY, user_id INTEGER NOT NULL REFERENCES users(id), project_id INTEGER REFERENCES projects(id), company_id INTEGER REFERENCES companies(id), date TIMESTAMPTZ NOT NULL, hours_worked TEXT NOT NULL, start_time TIMESTAMPTZ, end_time TIMESTAMPTZ, break_duration INTEGER DEFAULT 0, overtime_hours TEXT, location TEXT, tasks_completed TEXT, work_description TEXT, verified_by INTEGER REFERENCES users(id), approved_by INTEGER REFERENCES users(id), approved_at TIMESTAMPTZ, submitted_at TIMESTAMPTZ, status TEXT DEFAULT 'draft', signature_url TEXT, created_at TIMESTAMPTZ DEFAULT NOW() NOT NULL, updated_at TIMESTAMPTZ DEFAULT NOW() NOT NULL);
CREATE TABLE IF NOT EXISTS check_ins (id SERIAL PRIMARY KEY, user_id INTEGER NOT NULL REFERENCES users(id), project_id INTEGER REFERENCES projects(id), company_id INTEGER REFERENCES companies(id), timestamp TIMESTAMPTZ DEFAULT NOW() NOT NULL, type TEXT DEFAULT 'manual', latitude TEXT, longitude TEXT, accuracy TEXT, device_id TEXT, verification_method TEXT DEFAULT 'manual', verified BOOLEAN DEFAULT false, notes TEXT, photo_url TEXT, created_at TIMESTAMPTZ DEFAULT NOW() NOT NULL);
CREATE TABLE IF NOT EXISTS materials (id SERIAL PRIMARY KEY, name TEXT NOT NULL, category TEXT, description TEXT, quantity TEXT, unit TEXT, unit_price TEXT, total_price TEXT, supplier TEXT, status TEXT DEFAULT 'requested', location TEXT, delivery_date TIMESTAMPTZ, received_date TIMESTAMPTZ, received_by INTEGER REFERENCES users(id), inspected_by INTEGER REFERENCES users(id), quality_status TEXT DEFAULT 'pending', company_id INTEGER REFERENCES companies(id), project_id INTEGER REFERENCES projects(id), created_by INTEGER REFERENCES users(id), created_at TIMESTAMPTZ DEFAULT NOW() NOT NULL, updated_at TIMESTAMPTZ DEFAULT NOW() NOT NULL);
CREATE TABLE IF NOT EXISTS equipment (id SERIAL PRIMARY KEY, name TEXT NOT NULL, category TEXT, description TEXT, serial_number TEXT, manufacturer TEXT, model TEXT, purchase_date TIMESTAMPTZ, purchase_price INTEGER, status TEXT DEFAULT 'available', condition TEXT DEFAULT 'good', company_id INTEGER REFERENCES companies(id), project_id INTEGER REFERENCES projects(id), created_by INTEGER REFERENCES users(id), created_at TIMESTAMPTZ DEFAULT NOW() NOT NULL, updated_at TIMESTAMPTZ DEFAULT NOW() NOT NULL);
CREATE TABLE IF NOT EXISTS drawings (id SERIAL PRIMARY KEY, title TEXT NOT NULL, revision TEXT DEFAULT 'A', description TEXT, discipline TEXT DEFAULT 'general', status TEXT DEFAULT 'draft', sheet_number TEXT, drawing_number TEXT, file_url TEXT, file_type TEXT DEFAULT 'pdf', project_id INTEGER REFERENCES projects(id), company_id INTEGER REFERENCES companies(id), uploaded_by INTEGER REFERENCES users(id), uploaded_at TIMESTAMPTZ DEFAULT NOW() NOT NULL, created_at TIMESTAMPTZ DEFAULT NOW() NOT NULL);
CREATE TABLE IF NOT EXISTS files (id SERIAL PRIMARY KEY, name TEXT NOT NULL, original_name TEXT, mime_type TEXT, size INTEGER, url TEXT NOT NULL, thumbnail_url TEXT, caption TEXT, project_id INTEGER REFERENCES projects(id), company_id INTEGER REFERENCES companies(id), uploaded_by INTEGER REFERENCES users(id), file_type TEXT DEFAULT 'photo', uploaded_at TIMESTAMPTZ DEFAULT NOW() NOT NULL);
CREATE TABLE IF NOT EXISTS meetings (id SERIAL PRIMARY KEY, title TEXT NOT NULL, description TEXT, meeting_type TEXT DEFAULT 'general', status TEXT DEFAULT 'scheduled', location TEXT, scheduled_date TIMESTAMPTZ, start_time TIMESTAMPTZ, end_time TIMESTAMPTZ, notes TEXT, minutes TEXT, project_id INTEGER REFERENCES projects(id), company_id INTEGER REFERENCES companies(id), organizer_id INTEGER REFERENCES users(id), completed_at TIMESTAMPTZ, created_at TIMESTAMPTZ DEFAULT NOW() NOT NULL, updated_at TIMESTAMPTZ DEFAULT NOW() NOT NULL);
CREATE TABLE IF NOT EXISTS invoices (id SERIAL PRIMARY KEY, invoice_number TEXT NOT NULL, description TEXT, amount TEXT, subtotal TEXT, vat_amount TEXT, total TEXT, status TEXT DEFAULT 'draft', due_date TIMESTAMPTZ, paid_date TIMESTAMPTZ, payment_method TEXT, payment_reference TEXT, project_id INTEGER REFERENCES projects(id), company_id INTEGER REFERENCES companies(id), client_id INTEGER, created_by INTEGER REFERENCES users(id), created_at TIMESTAMPTZ DEFAULT NOW() NOT NULL, updated_at TIMESTAMPTZ DEFAULT NOW() NOT NULL);
CREATE TABLE IF NOT EXISTS purchase_orders (id SERIAL PRIMARY KEY, po_number TEXT NOT NULL, description TEXT, amount TEXT, status TEXT DEFAULT 'draft', ordered_at TIMESTAMPTZ, expected_delivery_date TIMESTAMPTZ, received_at TIMESTAMPTZ, approved_by INTEGER REFERENCES users(id), company_id INTEGER REFERENCES companies(id), project_id INTEGER REFERENCES projects(id), created_by INTEGER REFERENCES users(id), created_at TIMESTAMPTZ DEFAULT NOW() NOT NULL, updated_at TIMESTAMPTZ DEFAULT NOW() NOT NULL);
CREATE TABLE IF NOT EXISTS budgets (id SERIAL PRIMARY KEY, category TEXT NOT NULL, description TEXT, budgeted_amount TEXT, actual_amount TEXT, projected_amount TEXT, variance TEXT, status TEXT DEFAULT 'draft', project_id INTEGER REFERENCES projects(id), company_id INTEGER REFERENCES companies(id), created_by INTEGER REFERENCES users(id), created_at TIMESTAMPTZ DEFAULT NOW() NOT NULL, updated_at TIMESTAMPTZ DEFAULT NOW() NOT NULL);
CREATE TABLE IF NOT EXISTS cost_forecasts (id SERIAL PRIMARY KEY, month INTEGER NOT NULL, year INTEGER NOT NULL, budget TEXT, actual TEXT, forecast TEXT, variance TEXT, project_id INTEGER REFERENCES projects(id), company_id INTEGER REFERENCES companies(id), created_at TIMESTAMPTZ DEFAULT NOW() NOT NULL);
CREATE TABLE IF NOT EXISTS change_orders (id SERIAL PRIMARY KEY, co_number TEXT NOT NULL, title TEXT NOT NULL, description TEXT, reason TEXT, status TEXT DEFAULT 'draft', original_amount TEXT, revised_amount TEXT, impact_schedule TEXT, requested_by INTEGER REFERENCES users(id), approved_by INTEGER REFERENCES users(id), approved_at TIMESTAMPTZ, project_id INTEGER REFERENCES projects(id), company_id INTEGER REFERENCES companies(id), created_at TIMESTAMPTZ DEFAULT NOW() NOT NULL, updated_at TIMESTAMPTZ DEFAULT NOW() NOT NULL);
CREATE TABLE IF NOT EXISTS submittals (id SERIAL PRIMARY KEY, submittal_number TEXT NOT NULL, title TEXT NOT NULL, description TEXT, category TEXT, status TEXT DEFAULT 'draft', revision TEXT DEFAULT '0', specification_section TEXT, due_date TIMESTAMPTZ, approved_by INTEGER REFERENCES users(id), approved_at TIMESTAMPTZ, project_id INTEGER REFERENCES projects(id), company_id INTEGER REFERENCES companies(id), created_by INTEGER REFERENCES users(id), created_at TIMESTAMPTZ DEFAULT NOW() NOT NULL, updated_at TIMESTAMPTZ DEFAULT NOW() NOT NULL);
CREATE TABLE IF NOT EXISTS punch_items (id SERIAL PRIMARY KEY, number TEXT NOT NULL, title TEXT NOT NULL, description TEXT, location TEXT, trade TEXT, status TEXT DEFAULT 'open', priority TEXT DEFAULT 'medium', responsible INTEGER REFERENCES users(id), completed_by INTEGER REFERENCES users(id), completed_at TIMESTAMPTZ, verified_by INTEGER REFERENCES users(id), verified_at TIMESTAMPTZ, project_id INTEGER REFERENCES projects(id), company_id INTEGER REFERENCES companies(id), created_by INTEGER REFERENCES users(id), created_at TIMESTAMPTZ DEFAULT NOW() NOT NULL, updated_at TIMESTAMPTZ DEFAULT NOW() NOT NULL);
CREATE TABLE IF NOT EXISTS risk_register (id SERIAL PRIMARY KEY, title TEXT NOT NULL, description TEXT, category TEXT, probability INTEGER, impact INTEGER, risk_score INTEGER, mitigation TEXT, contingency TEXT, owner INTEGER REFERENCES users(id), status TEXT DEFAULT 'active', project_id INTEGER REFERENCES projects(id), company_id INTEGER REFERENCES companies(id), created_at TIMESTAMPTZ DEFAULT NOW() NOT NULL, updated_at TIMESTAMPTZ DEFAULT NOW() NOT NULL);
CREATE TABLE IF NOT EXISTS certifications (id SERIAL PRIMARY KEY, name TEXT NOT NULL, issuing_body TEXT, certificate_number TEXT, issue_date TIMESTAMPTZ, expiry_date TIMESTAMPTZ, status TEXT DEFAULT 'active', file_url TEXT, user_id INTEGER REFERENCES users(id), created_at TIMESTAMPTZ DEFAULT NOW() NOT NULL);
CREATE TABLE IF NOT EXISTS tenders (id SERIAL PRIMARY KEY, title TEXT NOT NULL, description TEXT, status TEXT DEFAULT 'draft', budget TEXT, deadline TIMESTAMPTZ, submission_date TIMESTAMPTZ, bid_amount TEXT, award_date TIMESTAMPTZ, project_id INTEGER REFERENCES projects(id), company_id INTEGER REFERENCES companies(id), created_by INTEGER REFERENCES users(id), created_at TIMESTAMPTZ DEFAULT NOW() NOT NULL, updated_at TIMESTAMPTZ DEFAULT NOW() NOT NULL);
CREATE TABLE IF NOT EXISTS delay_notes (id SERIAL PRIMARY KEY, title TEXT NOT NULL, reason TEXT, description TEXT, impact_days INTEGER, impact_cost TEXT, status TEXT DEFAULT 'active', project_id INTEGER REFERENCES projects(id), company_id INTEGER REFERENCES companies(id), created_by INTEGER REFERENCES users(id), created_at TIMESTAMPTZ DEFAULT NOW() NOT NULL, updated_at TIMESTAMPTZ DEFAULT NOW() NOT NULL);
CREATE TABLE IF NOT EXISTS notifications (id SERIAL PRIMARY KEY, user_id INTEGER NOT NULL REFERENCES users(id), type TEXT NOT NULL, title TEXT NOT NULL, message TEXT, data JSONB, read BOOLEAN DEFAULT false, read_at TIMESTAMPTZ, created_at TIMESTAMPTZ DEFAULT NOW() NOT NULL);
CREATE TABLE IF NOT EXISTS activity_feed (id SERIAL PRIMARY KEY, user_id INTEGER REFERENCES users(id), company_id INTEGER REFERENCES companies(id), project_id INTEGER REFERENCES projects(id), entity_type TEXT NOT NULL, entity_id INTEGER NOT NULL, action TEXT NOT NULL, old_data JSONB, new_data JSONB, created_at TIMESTAMPTZ DEFAULT NOW() NOT NULL);
CREATE TABLE IF NOT EXISTS subscriptions (id SERIAL PRIMARY KEY, company_id INTEGER NOT NULL REFERENCES companies(id), plan_id TEXT NOT NULL, plan_name TEXT, status TEXT DEFAULT 'trialing', current_period_start TIMESTAMPTZ, current_period_end TIMESTAMPTZ, created_at TIMESTAMPTZ DEFAULT NOW() NOT NULL);
CREATE TABLE IF NOT EXISTS ai_conversations (id SERIAL PRIMARY KEY, user_id INTEGER NOT NULL REFERENCES users(id), title TEXT, agent_type TEXT DEFAULT 'general', context JSONB, model TEXT DEFAULT 'gemini-2.5-pro', streaming_enabled BOOLEAN DEFAULT false, created_at TIMESTAMPTZ DEFAULT NOW() NOT NULL, updated_at TIMESTAMPTZ DEFAULT NOW() NOT NULL);
CREATE TABLE IF NOT EXISTS ai_messages (id SERIAL PRIMARY KEY, conversation_id INTEGER NOT NULL REFERENCES ai_conversations(id), role TEXT NOT NULL, content TEXT NOT NULL, model TEXT, tokens_used INTEGER, cost TEXT, latency_ms INTEGER, sources JSONB, created_at TIMESTAMPTZ DEFAULT NOW() NOT NULL);
CREATE TABLE IF NOT EXISTS webhooks (id SERIAL PRIMARY KEY, company_id INTEGER NOT NULL REFERENCES companies(id), name TEXT, url TEXT NOT NULL, events TEXT[], secret TEXT, active BOOLEAN DEFAULT true, created_at TIMESTAMPTZ DEFAULT NOW() NOT NULL);
CREATE TABLE IF NOT EXISTS bim_models (id SERIAL PRIMARY KEY, project_id INTEGER REFERENCES projects(id), name TEXT NOT NULL, description TEXT, file_url TEXT, file_type TEXT DEFAULT 'ifc', file_size INTEGER, thumbnail_url TEXT, company_id INTEGER REFERENCES companies(id), uploaded_by INTEGER REFERENCES users(id), uploaded_at TIMESTAMPTZ DEFAULT NOW() NOT NULL);
CREATE TABLE IF NOT EXISTS weather_logs (id SERIAL PRIMARY KEY, project_id INTEGER REFERENCES projects(id), date TIMESTAMPTZ NOT NULL, location TEXT, latitude TEXT, longitude TEXT, temperature TEXT, humidity TEXT, wind_speed TEXT, wind_direction TEXT, precipitation TEXT, conditions TEXT, uv_index TEXT, visibility TEXT, source TEXT DEFAULT 'openweather', created_at TIMESTAMPTZ DEFAULT NOW() NOT NULL);
CREATE TABLE IF NOT EXISTS contacts (id SERIAL PRIMARY KEY, name TEXT NOT NULL, email TEXT, phone TEXT, company TEXT, job_title TEXT, category TEXT DEFAULT 'supplier', notes TEXT, company_id INTEGER REFERENCES companies(id), created_at TIMESTAMPTZ DEFAULT NOW() NOT NULL);
CREATE TABLE IF NOT EXISTS quotes (id SERIAL PRIMARY KEY, quote_number TEXT NOT NULL, title TEXT NOT NULL, amount TEXT, status TEXT DEFAULT 'draft', valid_until TIMESTAMPTZ, client_id INTEGER, company_id INTEGER REFERENCES companies(id), created_by INTEGER REFERENCES users(id), created_at TIMESTAMPTZ DEFAULT NOW() NOT NULL, updated_at TIMESTAMPTZ DEFAULT NOW() NOT NULL);
CREATE TABLE IF NOT EXISTS documents (id SERIAL PRIMARY KEY, name TEXT NOT NULL, description TEXT, type TEXT DEFAULT 'rams', status TEXT DEFAULT 'draft', file_url TEXT, project_id INTEGER REFERENCES projects(id), company_id INTEGER REFERENCES companies(id), created_by INTEGER REFERENCES users(id), created_at TIMESTAMPTZ DEFAULT NOW() NOT NULL, updated_at TIMESTAMPTZ DEFAULT NOW() NOT NULL);
